import { bar_position, bar_styles } from '../bar/bar-encode';
import { bullet_levelmarker_position, bullet_levelmarker_styles } from './bullet-levelmarker-encode';
import { bullet_targetmarker_position, bullet_targetmarker_styles } from './bullet-targetmarker-encode';

export function bullet_encode_collectors() {
    bar_position.call(this);
    bullet_levelmarker_position.call(this);
    bullet_targetmarker_position.call(this);

    bar_styles.call(this);
    bullet_levelmarker_styles.call(this);
    bullet_targetmarker_styles.call(this);
}
